{
  "hooks": {
    "PermissionRequest" : [
        {
         "matcher": "",
         "hooks": [
          {
            "type": "command",
            "command": "terminal-notifier -message \"Permission required in $(basename $PWD)\" -title \"Claude Code\" -activate com.microsoft.VSCode -contentImage \"/Applications/Visual Studio Code.app/Contents/Resources/Code.icns\""
          }
        ]
       }
    ],
    "PostToolUse": [
      {
        "matcher": "Task",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code post-task"
          }
        ]
      },
      {
        "matcher": "TodoWrite",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code post-todo"
          }
        ]
      }
    ],
    "PreToolUse": [
      {
        "matcher": "Task",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code pre-task"
          }
        ]
      },
      {
        "matcher": "AskUserQuestion",
        "hooks": [
          {
            "type": "command",
            "command": "terminal-notifier -message \"Claude has a question in $(basename $PWD)\" -title \"Claude Code\" -activate com.microsoft.VSCode -contentImage \"/Applications/Visual Studio Code.app/Contents/Resources/Code.icns\""
          }
        ]
      },
      {
         "matcher": "ExitPlanMode",
         "hooks": [
          {
            "type": "command", 
            "command": "terminal-notifier -message \"Plan ready for review in $(basename $PWD)\" -title \"Claude Code\" -activate com.microsoft.VSCode -contentImage \"/Applications/Visual Studio Code.app/Contents/Resources/Code.icns\""
          }
        ]
       }
    ],
    "SessionEnd": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code session-end"
          }
        ]
      }
    ],
    "SessionStart": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code session-start"
          }
        ]
      }
    ],
    "Stop": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code stop"
          },
          {
            "type": "command", 
            "command": "terminal-notifier -message \"Task completed in $(basename $PWD)\" -title \"Claude Code\" -activate com.microsoft.VSCode -contentImage \"/Applications/Visual Studio Code.app/Contents/Resources/Code.icns\""
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code user-prompt-submit"
          }
        ]
      }
    ]
  },
  "permissions": {
    "deny": [
      "Read(./.entire/metadata/**)",
      "Bash(ruff*--unsafe-fixes*)",
      "Read(./.env)",
      "Read(./secrets/*)"
    ],
    "allow": [
      "Bash(git status*)",
      "Bash(git diff*)",
      "Bash(git log*)",
      "Bash(git add*)",
      "Bash(git commit*)",
      "Bash(git checkout*)",
      "Bash(git branch*)",
      "Bash(git stash*)",
      "Bash(.venv/bin/python -m pytest*)",
      "Bash(.venv/bin/python -m ruff*)",
      "Bash(.venv/bin/python main.py*)",
      "Bash(.venv/bin/uvicorn*)",
      "Bash(.venv/bin/pip)"
    ]
  }
}
